{
  "activities": [
    {
      "type": "activity",
      "title": "Reading Comprehension through Unseen Passage",
      "unit_name": "Reading Skills",
      "chapter_name": "Reading Skills",
      "details": "Students engage in reading discursive passages (400-450 words) and case-based factual passages with visual inputs (200-250 words). Activities include answering Multiple Choice Questions, Objective Type Questions, and Very Short Answer Questions to assess comprehension, interpretation, analysis, inference, evaluation, and vocabulary."
    },
    {
      "type": "activity",
      "title": "Grammar Accuracy Exercises",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students practice Determiners, Tenses, Modals, Subject-verb concord, and Reported speech through Gap Filling, Editing, and Transformation exercises. Focus is on accurate use of spelling, punctuation, and grammar."
    },
    {
      "type": "activity",
      "title": "Descriptive Paragraph Writing",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students write descriptive paragraphs (100-120 words) describing a person, event, or situation based on visual or verbal cues."
    },
    {
      "type": "activity",
      "title": "Story Writing and Diary Entry",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students write a story on a given cue/title or a diary entry (100-120 words) to demonstrate creative expression."
    },
    {
      "type": "activity",
      "title": "Reference to the Context Analysis",
      "unit_name": "Language through Literature",
      "chapter_name": "Reference to the Context",
      "details": "Students analyze extracts from Drama/Prose and Poetry, answering Multiple Choice Questions to assess interpretation, analysis, inference, evaluation, appreciation, and vocabulary."
    },
    {
      "type": "activity",
      "title": "Short Answer Type Questions Practice",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students answer short questions (40-50 words) from Beehive and Moments to assess interpretation, analysis, inference, and evaluation."
    },
    {
      "type": "activity",
      "title": "Long Answer Type Questions Practice",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students answer long questions (100-120 words) from Beehive and Moments focusing on creativity, imagination, extrapolation beyond the text, theme interpretation, or character sketches."
    },
    {
      "type": "activity",
      "title": "Role Play and Skit Performance",
      "unit_name": "Language through Literature",
      "chapter_name": "Beehive (Prose)",
      "details": "Students engage in role play, skits, and dramatization based on prescribed texts to encourage classroom interaction and expression of ideas."
    },
    {
      "type": "activity",
      "title": "Group Discussion and Debate",
      "unit_name": "Language through Literature",
      "chapter_name": "Beehive (Poems)",
      "details": "Students participate in group discussions to express ideas, defend views, and analyze themes from poems like 'The Road Not Taken' or 'No Men are Foreign'."
    },
    {
      "type": "activity",
      "title": "Listening and Speaking Practice",
      "unit_name": "Internal Assessment",
      "chapter_name": "Listening and Speaking",
      "details": "Regular practice of listening and speaking skills through activities designed to assess communication competence."
    }
  ],
  "projects": [
    {
      "title": "Art-Integrated Project: Role Play/Skit/Dramatization",
      "unit_name": "Internal Assessment",
      "chapter_name": "Listening and Speaking",
      "details": "Students create and perform art-integrated projects based on activities like role play, skits, or dramatization of texts from Beehive or Moments to assess listening and speaking skills (05 marks)."
    },
    {
      "title": "Creative Writing Portfolio",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Compilation of descriptive paragraphs, stories, and diary entries demonstrating creative expression and fluency."
    }
  ],
  "practicals": [
    {
      "title": "Listening and Speaking Assessment",
      "unit_name": "Internal Assessment",
      "chapter_name": "Listening and Speaking",
      "details": "Formal assessment of listening and speaking skills based on guidelines provided in Annexure I, focusing on communication competence."
    },
    {
      "title": "Grammar Application Practical",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Practical application of grammar rules through editing and transformation exercises to ensure accuracy in spelling, punctuation, and structure."
    }
  ]
}
